// 获取国家数据
function getCountryData(countryCode) {
  return postalData.countries.find(c => c.id === countryCode);
}

// 获取所有国家列表
function getAllCountries() {
  return postalData.countries;
}

// 搜索邮编
function searchPostalCode(countryCode, query) {
  const country = getCountryData(countryCode);
  if (!country) return [];
  
  const results = [];
  country.states.forEach(state => {
    state.cities.forEach(city => {
      city.postalCodes.forEach(pc => {
        if (pc.code.includes(query) || pc.area.toLowerCase().includes(query.toLowerCase())) {
          results.push({
            state: state.name,
            city: city.name,
            code: pc.code,
            area: pc.area,
            type: pc.type
          });
        }
      });
    });
  });
  
  return results;
}

// 导出数据（用于模块化环境）
if (typeof module !== "undefined" && module.exports) {
  module.exports = { postalData, countryNames, getCountryData, getAllCountries, searchPostalCode };
}

